"use strict";(self.webpackChunkprotocol_docs=self.webpackChunkprotocol_docs||[]).push([[931],{7387(l,i,e){e.r(i),e.d(i,{comp:()=>s,data:()=>t});var a=e(641);const n={},s=(0,e(6262).A)(n,[["render",function(l,i){return(0,a.uX)(),(0,a.CE)("div",null,[...i[0]||(i[0]=[(0,a.Fv)('<h1 id="perturbseq" tabindex="-1"><a class="header-anchor" href="#perturbseq"><span>PerturbSeq</span></a></h1><h2 id="stage-1-样品准备" tabindex="-1"><a class="header-anchor" href="#stage-1-样品准备"><span>Stage 1 样品准备</span></a></h2><h3 id="实验材料" tabindex="-1"><a class="header-anchor" href="#实验材料"><span>实验材料</span></a></h3><ul><li>Cell Suspension Buffer（CSB）</li><li>1000 μL 大孔径、低残留移液器吸头</li><li>细胞计数材料</li><li>1.5 ml Safe-Lock PCR Clean tubes (emulsion safe)</li></ul><h3 id="实验步骤" tabindex="-1"><a class="header-anchor" href="#实验步骤"><span>实验步骤</span></a></h3><ol><li>室温下350× g 离心 5 min（使用吊篮式转子）使细胞沉淀</li><li>小心弃去上清，准备加入 CSB 进行洗涤，以除去抑制性试剂</li><li>按照以下步骤清洗： a) 拿出 37℃预热的 CSB 并置于生物安全柜<br> b) 加 2 mL CSB，剩余 CSB 置于冰上<br> c) 使用 1000 µL大口径移液器吸头，缓慢移液 5 次以混合<br> d) 350× g 离心 5 min<br> e) 小心弃去上清</li><li>加入 100-500 µL 预冷 CSB</li><li>用尽可能轻的力度吹打混匀 10-15 次</li><li>计数细胞以确定细胞密度及活率，最终细胞密度：2.6e7 ~3.4e7/mL，活率&gt;90%；每次稀释都需要重复计数，一旦确定细胞浓度立即置于冰上准备捕获与裂解。</li></ol><h2 id="stage-2-单细胞捕获与化学裂解" tabindex="-1"><a class="header-anchor" href="#stage-2-单细胞捕获与化学裂解"><span>Stage 2 单细胞捕获与化学裂解</span></a></h2><h3 id="实验材料-1" tabindex="-1"><a class="header-anchor" href="#实验材料-1"><span>实验材料</span></a></h3><ul><li>CLB3</li><li>CPIP</li><li>PAR</li><li>RNI</li><li>0.5 mL Safe-Lock PCR Clean tubes (emulsion safe)</li><li>1 mL syringe</li><li>200 µL 大孔径、低残留移液器吸头</li><li>G22 blunt bottom syringe needle</li><li>0.5/1.5 mL combination tube stand (blue)</li></ul><h3 id="试剂预处理与仪器设置" tabindex="-1"><a class="header-anchor" href="#试剂预处理与仪器设置"><span>试剂预处理与仪器设置</span></a></h3><ol><li>CLB3——若观察到结晶，将其置于 25°C 的干浴器中，使其平衡至室温，涡旋 10 s， 然后瞬时离心；若无结晶，涡旋 5s，然后瞬时离心</li><li>CPIPs——瞬时离心 5s，冰上放置。</li><li>标记 0.5 mL PCR 管为 CLB3 管，每个反应准备一管（准备一管）。</li><li>将 PIPseq vortexer 设置为 3000 rpm 2min</li><li>根据样品类型使用不同选项设置盖子温度</li><li>干浴器选择 Prog. A，然后手动将盖子温度按照以下操作设置为 +5.0<br> a. 选择 Edit<br> b. 选择 LidMode 切换到+5.0<br> c. 选择 Save/Return</li><li>选择“Run”，将干浴器预热至适用裂解程序的保持温度。</li><li>选择“Lid On”预热干浴器盖子，当控制盖子温度时显示的是 LidOff</li></ol><h3 id="实验步骤-1" tabindex="-1"><a class="header-anchor" href="#实验步骤-1"><span>实验步骤</span></a></h3><ol><li>使用 200 μL 的大口径移液器吸头，缓慢移液 10 次以混合细胞悬液。</li><li>向 CPIP 管中的 CPIP 层缓慢加入 1 μL RNI（40 units）</li><li>向 CPIP 管中的 CPIP 层加入 4 μL 细胞悬液（密度：2.6 x 10 7 ~3.4 x 10 7 /mL，总共104000～13600）</li><li>将 200μL 移液枪调至 75 μL 缓慢吸吹 10 次混匀，以免产生气泡。</li><li>移除枪头时，沿管壁非常缓慢地打出最后一滴，以避免产生过多泡沫并减少 CPIP 的损失。</li><li>使用 1000 μL 的枪头，沿着 CPIP 管的侧壁加入 320 μL 的 PAR。</li><li>盖紧管盖，水平放入涡旋适配器的管位中，确保管子完全插入适配器中</li><li>3000 rpm 震荡 15 秒后手动停止；</li><li>旋转适配器切换至垂直位，以 3000 rpm 震荡 2 分钟；</li><li>将 PIP 管放入 combination tube stand（blue） 的 0.5 mL 侧，确保管子完全插入；</li><li>静置约 30 秒使乳液分层。</li><li>使用安装在 1 mL 注射器上的 G22 钝头注射针，按照如下步骤吸取并弃去多余的 PAR（下层相）<br> a. 将注射器针头缓缓穿过乳液（如图 A）降至试管底部。<br> b. 等待 5 s。<br> c. 抽吸下层液相，直至 CPIP 乳液底部接近管架 B 层，注意不要抽吸到任何乳液。<br> d. 移除针头时，在管子内壁擦拭一下。<br> e. 弃去针头和注射器到利器盒中<br> 注：在捕获和裂解步骤的剩余步骤内，请勿将 PIP 管置于冰上，以免裂解试剂沉淀</li><li>制备化学裂解乳液（配制一个样品的量）：</li></ol><ul><li>CLB3（90 μL）</li><li>PAR（270 μL）<br> 注：切勿大量配制化学裂解乳液。每个样本应分别单独配制。</li></ul><ol start="14"><li>涡旋化学裂解乳液 10s 混匀 在转移前充分混匀 CLB3 和 PAR 对形成乳液至关重要</li><li>用 1000 μL 低残留枪头立即将每个 CLB3 管中的全部化学裂解乳液移至每个 CPIP 管中</li><li>颠倒混匀 10-15 次</li><li>将 CPIP 管置于预热的干浴器上。</li><li>选择 Skip，然后选择 Yes 以运行裂解程序 Prog. A</li></ol><h2 id="stage-3-mrna分离" tabindex="-1"><a class="header-anchor" href="#stage-3-mrna分离"><span>Stage 3 mRNA分离</span></a></h2><h3 id="实验试剂" tabindex="-1"><a class="header-anchor" href="#实验试剂"><span>实验试剂</span></a></h3><ul><li>BBF(Breaking Buffer)</li><li>DPR(Departitioning Reagent)</li><li>PWB1(Washing Buffer)</li><li>0.5 ml Safe-Lock PCR Clean tubes (emulsion safe)</li><li>1.5 ml Safe-Lock PCR Clean tubes (emulsion safe)</li><li>1 ml syringe</li><li>G22 blunt bottom syringe needle</li><li>0.5/1.5 ml combination tube stand (blue)</li></ul>',18)])])}]]),t=JSON.parse('{"path":"/posts/PerturbSeq.html","title":"PerturbSeq","lang":"zh-CN","frontmatter":{"date":"2022-01-06T00:00:00.000Z","category":["Category A","Category B"],"tag":["tag A","tag B"]},"headers":[{"level":2,"title":"Stage 1 样品准备","slug":"stage-1-样品准备","link":"#stage-1-样品准备","children":[{"level":3,"title":"实验材料","slug":"实验材料","link":"#实验材料","children":[]},{"level":3,"title":"实验步骤","slug":"实验步骤","link":"#实验步骤","children":[]}]},{"level":2,"title":"Stage 2 单细胞捕获与化学裂解","slug":"stage-2-单细胞捕获与化学裂解","link":"#stage-2-单细胞捕获与化学裂解","children":[{"level":3,"title":"实验材料","slug":"实验材料-1","link":"#实验材料-1","children":[]},{"level":3,"title":"试剂预处理与仪器设置","slug":"试剂预处理与仪器设置","link":"#试剂预处理与仪器设置","children":[]},{"level":3,"title":"实验步骤","slug":"实验步骤-1","link":"#实验步骤-1","children":[]}]},{"level":2,"title":"Stage 3 mRNA分离","slug":"stage-3-mrna分离","link":"#stage-3-mrna分离","children":[{"level":3,"title":"实验试剂","slug":"实验试剂","link":"#实验试剂","children":[]}]}],"git":{"updatedTime":1784001003000,"contributors":[{"name":"zichongxu-ustc","username":"zichongxu-ustc","email":"zchong_xu@mail.ustc.edu.cn","commits":1,"url":"https://github.com/zichongxu-ustc"}],"changelog":[{"hash":"0bc58c9f35d8dc24d4c01d3b0370ba429a8eb1e7","time":1784001003000,"email":"zchong_xu@mail.ustc.edu.cn","author":"zichongxu-ustc","message":"Regular upload"}]},"filePathRelative":"posts/PerturbSeq.md","excerpt":"\\n<h2>Stage 1 样品准备</h2>\\n<h3>实验材料</h3>\\n<ul>\\n<li>Cell Suspension Buffer（CSB）</li>\\n<li>1000 μL 大孔径、低残留移液器吸头</li>\\n<li>细胞计数材料</li>\\n<li>1.5 ml Safe-Lock PCR Clean tubes (emulsion safe)</li>\\n</ul>\\n<h3>实验步骤</h3>\\n<ol>\\n<li>室温下350× g 离心 5 min（使用吊篮式转子）使细胞沉淀</li>\\n<li>小心弃去上清，准备加入 CSB 进行洗涤，以除去抑制性试剂</li>\\n<li>按照以下步骤清洗：\\na)  拿出 37℃预热的 CSB 并置于生物安全柜<br>\\nb)  加 2 mL CSB，剩余 CSB 置于冰上<br>\\nc)  使用 1000 µL大口径移液器吸头，缓慢移液 5 次以混合<br>\\nd)  350× g 离心 5 min<br>\\ne)  小心弃去上清</li>\\n<li>加入 100-500 µL 预冷 CSB</li>\\n<li>用尽可能轻的力度吹打混匀 10-15 次</li>\\n<li>计数细胞以确定细胞密度及活率，最终细胞密度：2.6e7 ~3.4e7/mL，活率&gt;90%；每次稀释都需要重复计数，一旦确定细胞浓度立即置于冰上准备捕获与裂解。</li>\\n</ol>"}')}}]);